<body>
<div id="nav"></div>
<div class="layout">
  <div class="dt-main">
    <div class="page-header">
      <div class="page-title">🧠 Deep Think</div>
      <div class="page-sub">Multi-agent debate & synthesis. Throw a topic — 3 agents analyze, debate, and produce a unified plan.</div>
    </div>

    <div class="input-area">
      <textarea class="topic-input" id="topicInput" placeholder='e.g. "Should we launch a freemium tier for DataFlow?" or "Technical architecture for OCR pipeline"' rows="3"></textarea>
    </div>

    <div class="agents-section">
      <div class="agents-label">
        <span>Select Debate Agents (3 recommended)</span>
        <button onclick="toggleAllAgents()">Select All / None</button>
      </div>
      <div class="agents-grid" id="agentsGrid"></div>
    </div>

    <!-- Rounds Slider -->
    <div style="margin-bottom:20px;padding:16px 20px;border-radius:12px;border:1px solid var(--glass-border,rgba(255,255,255,.08));background:var(--glass,rgba(255,255,255,.02))">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
        <span style="font-size:11px;font-weight:700;color:var(--text-secondary,#888);text-transform:uppercase;letter-spacing:1px">Debate Rounds</span>
        <span id="roundsValue" style="font-size:18px;font-weight:800;color:var(--color-primary,#63ebff);font-family:var(--font-mono,monospace)">3</span>
      </div>
      <input type="range" id="roundsSlider" min="1" max="7" value="3" style="width:100%;accent-color:var(--color-primary,#63ebff);cursor:pointer">
      <div style="display:flex;justify-content:space-between;font-size:9px;color:var(--text-tertiary,#555);margin-top:4px">
        <span>1 · Quick</span>
        <span>3 · Standard</span>
        <span>5 · Deep</span>
        <span>7 · Max</span>
      </div>
      <div id="roundsDesc" style="font-size:11px;color:var(--text-tertiary,#666);margin-top:8px">Standard: Initial → Debate → Synthesis</div>
    </div>

    <button class="start-btn" id="startBtn" onclick="startDeepThink()">🧠 Start Deep Think</button>

    <div class="progress-area" id="progressArea">
      <div class="progress-step" id="step1"><span class="step-icon">1</span> Phase 1: Initial Analysis — agents forming positions...</div>
      <div class="progress-step" id="step2"><span class="step-icon">2</span> Phase 2: Debate — agents challenging each other...</div>
      <div class="progress-step" id="step3"><span class="step-icon">3</span> Phase 3: Synthesis — producing unified plan...</div>
    </div>

    <div class="results-area" id="resultsArea">
      <div id="initialCards"></div>
      <div id="debateCards"></div>
      <div id="synthesisCard"></div>
      <div class="action-row" id="actionRow" style="display:none">
        <button class="action-btn" id="visualBtn" onclick="generateVisual()">🎨 Generate Visual Plan</button>
        <button class="action-btn" onclick="saveToObsidian()">📝 Save to Obsidian</button>
      </div>
    </div>

    <div class="history-section">
      <div class="history-title">📜 Past Deep Thinks</div>
      <div id="historyList"><div class="history-empty">No deep thinks yet. Start one above!</div></div>
    </div>
  </div>
</div>

<script src="/shared/marked.min.js"></script>
