<script type="module">
import { initPage, api, toast, escHtml, timeAgo, $ } from '/shared/core.js';
import { renderNav } from '/shared/nav.js';
import { renderMarkdown } from '/shared/markdown.js';
import { initTransitions } from '/shared/transitions.js';

await initPage();
renderNav('deep-think');
initTransitions();

const AGENT_META = {
  rafael:  { name:'Rafael',  emoji:'🧭', role:'The Architect',   color:'#34A853' },
  gabriel: { name:'Gabriel', emoji:'📣', role:'The Voice',       color:'#FBBC04' },
  samael:  { name:'Samael',  emoji:'⚔️', role:'The Prosecutor',  color:'#E91E63' },
  uriel:   { name:'Uriel',   emoji:'🔥', role:'The Validator',   color:'#FF6D00' },
  raguel:  { name:'Raguel',  emoji:'🤝', role:'The Friend',      color:'#00BCD4' },
  sarael:  { name:'Sarael',  emoji:'📜', role:'The Scribe',      color:'#9C27B0' },
  sophia:  { name:'Sophia',  emoji:'📚', role:'The Scholar',     color:'#3F51B5' },
  metis:   { name:'Metis',   emoji:'🔍', role:'The Librarian',   color:'#00897B' },
  azrael:  { name:'Azrael',  emoji:'💰', role:'The Auditor',     color:'#CDDC39' },
  remiel:  { name:'Remiel',  emoji:'⚖️', role:'The Sentry',      color:'#607D8B' },
  zadkiel: { name:'Zadkiel', emoji:'🎨', role:'The Builder',     color:'#FF5722' },
  michael: { name:'Michael', emoji:'🛡️', role:'Wise Advisor',    color:'#4285F4' },
};

const DEFAULT_AGENTS = ['rafael', 'uriel', 'samael'];
let selectedAgents = new Set(DEFAULT_AGENTS);
let isRunning = false;
let currentResult = null;

// Render agent chips
function renderAgentChips() {
  const grid = $('agentsGrid'); if (!grid) return; grid.innerHTML = '';
  for (const [id, meta] of Object.entries(AGENT_META)) {
    const chip = document.createElement('div');
    chip.className = 'agent-chip' + (selectedAgents.has(id) ? ' selected' : '');
    chip.style.setProperty('--agent-color', meta.color);
    chip.onclick = () => { toggleAgent(id, chip); };
    chip.innerHTML = `<span class="dot" style="background:${meta.color}"></span><span class="agent-name">${meta.emoji} ${meta.name}</span><span class="agent-role">· ${meta.role}</span>`;
    grid.appendChild(chip);
  }
}

function toggleAgent(id, chip) {
  if (selectedAgents.has(id)) { selectedAgents.delete(id); chip.classList.remove('selected'); }
  else { selectedAgents.add(id); chip.classList.add('selected'); }
}

window.toggleAllAgents = function() {
  const allSelected = selectedAgents.size === Object.keys(AGENT_META).length;
  selectedAgents = allSelected ? new Set() : new Set(Object.keys(AGENT_META));
  renderAgentChips();
};

// Rounds slider
const roundsDescriptions = {
  1: 'Quick: Initial analysis only → Synthesis',
  2: 'Light: Initial → 1 debate round → Synthesis',
  3: 'Standard: Initial → Debate → Synthesis',
  4: 'Extended: Initial → Debate → Counter-debate → Synthesis',
  5: 'Deep: Initial → Debate → Counter → Final positions → Synthesis',
  6: 'Thorough: 4 debate rounds + edge case analysis → Synthesis',
  7: 'Maximum: 5 debate rounds with full convergence → Synthesis'
};
const slider = $('roundsSlider');

