if (slider) {
  slider.addEventListener('input', function() {
    const v = parseInt(this.value);
    const valEl = $('roundsValue');
    const descEl = $('roundsDesc');
    if (valEl) valEl.textContent = v;
    if (descEl) descEl.textContent = roundsDescriptions[v] || '';
  });
}

// Start Deep Think
window.startDeepThink = async function() {
  const topic = $('topicInput')?.value.trim();
  if (!topic) { toast('Enter a topic first', 'warning'); return; }
  if (selectedAgents.size < 2) { toast('Select at least 2 agents', 'warning'); return; }
  if (isRunning) return;

  isRunning = true;
  const btn = $('startBtn');
  btn.textContent = '⏳ Deep Think in progress...';
  btn.classList.add('running');
  btn.disabled = true;

  const progress = $('progressArea');
  progress.style.display = '';
  $('resultsArea').style.display = 'none';
  $('actionRow').style.display = 'none';

  // Activate step 1
  setStep(1);

  try {
    const agents = [...selectedAgents];
    const rounds = parseInt($('roundsSlider')?.value) || 3;
    const { data, error } = await api('deep-think', {
      method: 'POST',
      body: { topic, agents, rounds }
    });

    if (error || !data?.ok) {
      toast(error || data?.error || 'Deep Think failed', 'danger');
      resetBtn();
      return;
    }

    currentResult = data.result;

    // Show results
    setStep(3, true); // All done
    showResults(data.result);
    loadHistory();
    toast('🧠 Deep Think complete!', 'success');

  } catch (err) {
    toast('Error: ' + err.message, 'danger');
  }
  resetBtn();
};

function resetBtn() {
  isRunning = false;
  const btn = $('startBtn');
  btn.textContent = '🧠 Start Deep Think';
  btn.classList.remove('running');
  btn.disabled = false;
}

function setStep(n, allDone) {
  for (let i = 1; i <= 3; i++) {
    const el = $('step' + i);
    if (!el) continue;
    el.classList.remove('active', 'done');
    if (allDone || i < n) el.classList.add('done');
    else if (i === n) el.classList.add('active');
  }
}

function showResults(result) {
  const area = $('resultsArea');
  area.style.display = '';

  // Initial takes
  const initDiv = $('initialCards');
  initDiv.innerHTML = '<div class="phase-title">Phase 1: Initial Analysis <span class="badge">Round 1</span></div>';
  for (const r of result.phases.initial || []) {
    const meta = AGENT_META[r.agentId] || { name: r.agentId, emoji: '🤖', color: '#888', role: '' };
    initDiv.innerHTML += `<div class="agent-card">
      <div class="agent-card-header">
        <span class="dot" style="background:${meta.color};color:${meta.color}"></span>
        <span class="name" style="color:${meta.color}">${meta.name}</span>
        <span class="role">${meta.role}</span>
        <span class="phase-badge" style="background:rgba(99,102,241,.1);color:var(--color-primary)">Initial</span>
      </div>
      <div class="agent-card-body">${renderMarkdown(r.response || '')}</div>
    </div>`;
  }

  // Debate
  const debateDiv = $('debateCards');
  debateDiv.innerHTML = '<div class="phase-title">Phase 2: Debate <span class="badge" style="background:rgba(245,158,11,.1);color:#f59e0b">Round 2</span></div>';

[99 more lines in file. Use offset=401 to continue.]

  for (const r of result.phases.debate || []) {
    const meta = AGENT_META[r.agentId] || { name: r.agentId, emoji: '🤖', color: '#888', role: '' };
    debateDiv.innerHTML += `<div class="agent-card">
      <div class="agent-card-header">
        <span class="dot" style="background:${meta.color};color:${meta.color}"></span>
        <span class="name" style="color:${meta.color}">${meta.name}</span>
        <span class="role">${meta.role}</span>
        <span class="phase-badge" style="background:rgba(245,158,11,.1);color:#f59e0b">Debate</span>
      </div>
      <div class="agent-card-body">${renderMarkdown(r.response || '')}</div>
    </div>`;
  }

  // Synthesis
  const synthDiv = $('synthesisCard');
  synthDiv.innerHTML = `<div class="phase-title">Phase 3: Synthesis <span class="badge" style="background:rgba(52,211,153,.1);color:var(--color-accent)">Final</span></div>
    <div class="synthesis-card">
      <div class="synthesis-header"><span class="icon">✨</span><span class="label">Deep Think Synthesis</span></div>
      <div class="synthesis-body">${renderMarkdown(result.synthesis || '')}</div>
    </div>`;

  $('actionRow').style.display = '';
  area.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

// Generate visual plan
window.generateVisual = async function() {
  if (!currentResult) { toast('No deep think result', 'warning'); return; }
  const btn = $('visualBtn');
  btn.disabled = true;
  btn.textContent = '⏳ Generating...';

  const { data, error } = await api('deep-think/' + currentResult.id + '/visual', { method: 'POST' });
  btn.disabled = false;
  btn.textContent = '🎨 Generate Visual Plan';

  if (error || !data?.ok) {
    toast(error || 'Failed to generate visual', 'danger');
    return;
  }

  toast('🎨 Visual plan generated!', 'success');
  window.open(data.url, '_blank');
};

// Save to Obsidian
window.saveToObsidian = async function() {
  if (!currentResult) return;
  const text = `# Deep Think: ${currentResult.topic}\n\n## Agents: ${currentResult.agents.join(', ')}\n\n## Synthesis\n\n${currentResult.synthesis}`;
  const { error } = await api('obsidian/save', {
    method: 'POST',
    body: { title: 'Deep Think: ' + currentResult.topic.slice(0, 50), agent: 'Deep Think', text, tags: ['deep-think', 'magi'] }
  });
  if (error) { toast(error, 'danger'); return; }
  toast('📝 Saved to Obsidian!', 'success');
};

// History
async function loadHistory() {
  const { data } = await api('deep-think');
  const list = $('historyList');
  if (!data?.items?.length) { list.innerHTML = '<div class="history-empty">No deep thinks yet. Start one above!</div>'; return; }
  list.innerHTML = data.items.map(item => `
    <div class="history-item" onclick="window._loadDT('${item.id}')">
      <span class="icon">🧠</span>
      <div class="info">
        <div class="topic">${escHtml(item.topic)}</div>
        <div class="meta"><span>${item.agents?.length || 0} agents</span><span>·</span><span>${timeAgo(item.createdAt)}</span></div>
      </div>
    </div>
  `).join('');
}

window._loadDT = function(id) {
  // Find from API and display
  api('deep-think').then(({ data }) => {
    if (!data?.items) return;
    const item = data.items.find(i => i.id === id);
    if (!item) return;
    currentResult = item;
    $('topicInput').value = item.topic;
    $('progressArea').style.display = 'none';
    showResults(item);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
};

// Init
renderAgentChips();
loadHistory();

$('topicInput')?.addEventListener('keydown', e => {
  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); window.startDeepThink(); }
});
</script>
