/* Progress */
.progress-area{margin:24px 0;display:none}
.progress-phase{margin-bottom:16px}
.progress-phase-title{font-size:12px;font-weight:700;color:var(--text-secondary);text-transform:uppercase;letter-spacing:.8px;padding:6px 0 8px;display:flex;align-items:center;gap:8px}
.progress-phase-title .phase-num{font-size:10px;padding:2px 8px;border-radius:999px;background:rgba(99,102,241,.1);color:var(--color-primary)}
.progress-phase.phase-done .progress-phase-title{color:var(--color-accent)}
.progress-phase.phase-done .phase-num{background:rgba(52,211,153,.1);color:var(--color-accent)}

.progress-step{display:flex;align-items:center;gap:10px;padding:8px 14px;border-radius:10px;margin-bottom:4px;font-size:13px;color:var(--text-tertiary);transition:all .3s}
.progress-step.waiting{opacity:.45}
.progress-step.active{background:rgba(99,102,241,.06);color:var(--color-primary);font-weight:600}
.progress-step.done{color:var(--color-accent)}

.progress-step .step-icon{width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;border:1px solid var(--glass-border);flex-shrink:0;transition:all .3s}
.progress-step.waiting .step-icon{opacity:.4}
.progress-step.active .step-icon{background:var(--color-primary-dim);border-color:var(--color-primary);animation:pulseDot 1.5s ease-in-out infinite}
.progress-step.done .step-icon{background:rgba(52,211,153,.1);border-color:var(--color-accent);animation:none}
@keyframes pulseDot{0%,100%{transform:scale(1);opacity:1}50%{transform:scale(1.2);opacity:.7}}

.progress-step .step-label{flex:1;min-width:0;display:flex;align-items:center;gap:6px}
.progress-step .step-agent-name{font-weight:600}
.progress-step .step-timer{font-size:10px;font-family:var(--font-mono,monospace);color:var(--text-tertiary);margin-left:auto;min-width:36px;text-align:right}
.progress-step.active .step-timer{color:var(--color-primary)}
.progress-step.done .step-timer{color:var(--color-accent)}

/* Overall progress bar */
.progress-bar-wrap{margin:12px 0 16px;padding:0 14px}
.progress-bar-outer{height:4px;border-radius:4px;background:rgba(255,255,255,.06);overflow:hidden}
.progress-bar-inner{height:100%;border-radius:4px;background:linear-gradient(90deg,#f59e0b,#6366f1,#34d399);background-size:200% 100%;animation:progressShimmer 2s linear infinite;transition:width .5s ease-out;width:0%}
@keyframes progressShimmer{0%{background-position:0% 0}100%{background-position:200% 0}}
.progress-elapsed{font-size:11px;color:var(--text-tertiary);text-align:center;margin-top:8px;font-family:var(--font-mono,monospace)}

