  const phase1Steps = agents.map(id => {
    const meta = AGENT_META[id] || { name: id, emoji: '🤖', color: '#888' };
    return { id: `initial-${id}`, label: `${meta.emoji} ${meta.name} thinking...`, doneLabel: `${meta.emoji} ${meta.name} — position formed`, color: meta.color, avgTime: 15 + Math.random() * 8 };
  });
  phases.push({ name: 'Initial Analysis', steps: phase1Steps });

  // Phase 2: Debate — (rounds - 2) extra rounds, each agent responds per round
  const debateRounds = Math.max(rounds - 2, 1);
  for (let r = 0; r < debateRounds; r++) {
    const roundSteps = agents.map(id => {
      const meta = AGENT_META[id] || { name: id, emoji: '🤖', color: '#888' };
      return { id: `debate-r${r}-${id}`, label: `${meta.emoji} ${meta.name} responding...`, doneLabel: `${meta.emoji} ${meta.name} — response complete`, color: meta.color, avgTime: 18 + Math.random() * 10 };
    });
    phases.push({ name: debateRounds === 1 ? 'Debate' : `Debate Round ${r + 1}`, steps: roundSteps });
  }

  // Phase 3: Synthesis
  phases.push({ name: 'Synthesis', steps: [{ id: 'synthesis', label: '✨ Sarael synthesizing all positions...', doneLabel: '✨ Synthesis complete', color: '#9C27B0', avgTime: 20 + Math.random() * 10 }] });

  return phases;
}

function renderProgressSteps(phases) {
  const container = $('progressSteps');
  container.innerHTML = '';
  phases.forEach((phase, pi) => {
    const phaseDiv = document.createElement('div');
    phaseDiv.className = 'progress-phase';
    phaseDiv.id = `progress-phase-${pi}`;
    phaseDiv.innerHTML = `<div class="progress-phase-title"><span class="phase-num">Phase ${pi + 1}</span> ${phase.name}</div>`;
    phase.steps.forEach((step, si) => {
      const stepDiv = document.createElement('div');
      stepDiv.className = 'progress-step waiting';
      stepDiv.id = `pstep-${pi}-${si}`;
      stepDiv.innerHTML = `<span class="step-icon" style="border-color:${step.color}30">○</span><span class="step-label"><span class="step-agent-name">${step.label}</span></span><span class="step-timer"></span>`;
      phaseDiv.appendChild(stepDiv);
    });
    container.appendChild(phaseDiv);
  });
  // Reset progress bar
  const bar = $('progressBar');
  if (bar) bar.style.width = '0%';
  const elapsed = $('progressElapsed');
  if (elapsed) elapsed.textContent = '0:00 elapsed';
}

function startProgressAnimation(phases) {
  const allSteps = [];
  phases.forEach((phase, pi) => {
    phase.steps.forEach((step, si) => {
      allSteps.push({ pi, si, step });
    });
  });
  const totalSteps = allSteps.length;
  let currentIdx = 0;
  let finished = false;
  const startTime = Date.now();
  let stepStartTime = Date.now();
  let stepTimers = [];

  // Global elapsed timer
  const elapsedInterval = setInterval(() => {
    if (finished) return;
    const sec = Math.floor((Date.now() - startTime) / 1000);
    const m = Math.floor(sec / 60);
    const s = sec % 60;
    const el = $('progressElapsed');
    if (el) el.textContent = `${m}:${s.toString().padStart(2, '0')} elapsed`;
  }, 1000);

  function activateStep(idx) {
    if (idx >= totalSteps || finished) return;
    const { pi, si, step } = allSteps[idx];
    const el = document.getElementById(`pstep-${pi}-${si}`);
    if (!el) return;

    // Mark previous step done
    if (idx > 0) markDone(idx - 1);

    el.className = 'progress-step active';
    el.querySelector('.step-icon').innerHTML = '◉';
    el.querySelector('.step-icon').style.borderColor = step.color;
    el.querySelector('.step-icon').style.background = step.color + '20';
    stepStartTime = Date.now();

    // Per-step elapsed timer
    const timerSpan = el.querySelector('.step-timer');
    const timerInt = setInterval(() => {
      if (finished) { clearInterval(timerInt); return; }
      const s = Math.floor((Date.now() - stepStartTime) / 1000);
      if (timerSpan) timerSpan.textContent = `${s}s`;
    }, 1000);
    stepTimers.push(timerInt);

    // Update progress bar
    const pct = Math.min(((idx + 0.5) / totalSteps) * 100, 95);
    const bar = $('progressBar');
    if (bar) bar.style.width = pct + '%';

    // Mark phase title if all previous phases are done
    for (let p = 0; p < pi; p++) {
      const phaseEl = document.getElementById(`progress-phase-${p}`);
      if (phaseEl) phaseEl.classList.add('phase-done');
    }

    // Scroll step into view
    el.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }

  function markDone(idx) {
    const { pi, si, step } = allSteps[idx];
    const el = document.getElementById(`pstep-${pi}-${si}`);
    if (!el) return;
    el.className = 'progress-step done';
    el.querySelector('.step-icon').innerHTML = '✓';
    el.querySelector('.step-icon').style.borderColor = 'var(--color-accent)';
    el.querySelector('.step-icon').style.background = 'rgba(52,211,153,.1)';
    const nameSpan = el.querySelector('.step-agent-name');
    if (nameSpan) nameSpan.textContent = step.doneLabel;
  }

  function scheduleNext() {
    if (currentIdx >= totalSteps || finished) return;
    activateStep(currentIdx);
    const { step } = allSteps[currentIdx];
    currentIdx++;
    // Schedule next step with some randomness
    const delay = (step.avgTime + (Math.random() * 6 - 3)) * 1000;
    setTimeout(() => scheduleNext(), delay);
  }

  // Start
  scheduleNext();

  return {
    finish() {
      finished = true;
      clearInterval(elapsedInterval);
      stepTimers.forEach(t => clearInterval(t));
      // Mark all steps done
      allSteps.forEach((s, idx) => markDone(idx));
      // Mark all phases done
      phases.forEach((_, pi) => {
        const phaseEl = document.getElementById(`progress-phase-${pi}`);
        if (phaseEl) phaseEl.classList.add('phase-done');
      });
      // Progress bar 100%
      const bar = $('progressBar');
      if (bar) bar.style.width = '100%';
      // Final elapsed
      const sec = Math.floor((Date.now() - startTime) / 1000);
      const m = Math.floor(sec / 60);
      const s = sec % 60;
      const el = $('progressElapsed');
      if (el) el.textContent = `Done in ${m}:${s.toString().padStart(2, '0')}`;
    }
  };
}

