window._loadDT = function(id) {
  // Find from API and display
  api('deep-think').then(({ data }) => {
    if (!data?.items) return;
    const item = data.items.find(i => i.id === id);
    if (!item) { toast('Deep Think not found', 'warning'); return; }
    currentResult = item;
    const topicInput = $('topicInput');
    if (topicInput) topicInput.value = item.topic || '';
    const progressArea = $('progressArea');
    if (progressArea) progressArea.style.display = 'none';
    showResults(item);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }).catch(err => {
    console.error('Failed to load deep think:', err);
    toast('Failed to load deep think', 'danger');
  });
};

